/// <summary>
/// [OBSOLETO — Task #5] Segundo o GDD, Sussurros da Terra NÃO são pickups
/// físicos no mundo. São adquiridos exclusivamente comprando-os ao NPC
/// "Contador de Histórias" com Ecos Perdidos. Este componente contradiz o GDD
/// e não deve ser colocado em nenhuma cena ou prefab.
///
/// Se precisas de registar um Sussurro (ex: em tests), chama directamente
/// <c>PlayerProgress.Instance.AddWhisperFound(area)</c> a partir de uma
/// Action de diálogo.
///
/// O validador de dados (<see cref="GameDataValidatorBuildPreprocess"/> /
/// <see cref="GameDataValidatorWindow"/>) emite um aviso se este componente
/// for encontrado em qualquer prefab ou cena.
/// </summary>
[System.Obsolete("SussurroDaTerraPickup contradiz o GDD: Sussurros são comprados ao Contador de Histórias, não são pickups de chão. Usa uma Action de diálogo para chamar PlayerProgress.AddWhisperFound.")]
public class SussurroDaTerraPickup : PickupBase
{
    public override PickupType Type => PickupType.SussurroDaTerra;

    protected override void GrantReward()
    {
        if (area != null) PlayerProgress.Instance?.AddWhisperFound(area);
    }
}
